export class ProdutosComponent {
  constructor(estoqueService, relatorioService, auditoriaService) {
    this.estoqueService = estoqueService;
    this.relatorioService = relatorioService;
    this.auditoriaService = auditoriaService;
    this.produtos = [];
    this.loading = false;
    this.error = '';
    this.showForm = false;
    this.editingId = null;
    this.filtroCodigo = '';
    this.filtroDescricao = '';
    this.filtroSaldo = '';
    // Paginação
    this.paginaAtual = 1;
    this.registrosPorPagina = 10;
    this.totalPaginas = 0;
    this.ordem = 'asc';
    this.ordenarPor = 'codigo';
    this.form = {
      codigo: 0,
      descricao: '',
      saldo: 0
    };
  }
  ngOnInit() {
    this.carregarProdutos();
  }
  carregarProdutos() {
    this.loading = true;
    this.error = '';
    this.estoqueService.obterTodosProdutos().subscribe({
      next: data => {
        this.produtos = data;
        this.loading = false;
      },
      error: err => {
        this.error = 'Erro ao carregar produtos: ' + (err.message || 'Erro desconhecido');
        this.loading = false;
      }
    });
  }
  abrirFormulario() {
    this.showForm = true;
    this.editingId = null;
    this.form = {
      codigo: 0,
      descricao: '',
      saldo: 0
    };
  }
  fecharFormulario() {
    this.showForm = false;
    this.form = {
      codigo: 0,
      descricao: '',
      saldo: 0
    };
  }
  salvarProduto() {
    if (!this.form.descricao.trim()) {
      this.error = 'Descrição é obrigatória';
      return;
    }
    this.loading = true;
    this.error = '';
    const request = {
      codigo: this.form.codigo,
      descricao: this.form.descricao,
      saldo: this.form.saldo
    };
    if (this.editingId) {
      this.estoqueService.atualizarProduto(this.editingId, request).subscribe({
        next: () => {
          this.auditoriaService.registrar('Atualizar Produto', `Produto ${this.form.descricao} atualizado (Código: ${this.form.codigo}, Saldo: ${this.form.saldo})`, 'atualizar');
          this.carregarProdutos();
          this.fecharFormulario();
        },
        error: err => {
          this.error = 'Erro ao atualizar produto: ' + (err.message || 'Erro desconhecido');
          this.auditoriaService.registrar('Atualizar Produto - Erro', `Falha ao atualizar ${this.form.descricao}: ${this.error}`, 'outro');
          this.loading = false;
        }
      });
    } else {
      this.estoqueService.criarProduto(request).subscribe({
        next: () => {
          this.auditoriaService.registrar('Criar Produto', `Novo produto ${this.form.descricao} criado (Código: ${this.form.codigo}, Saldo: ${this.form.saldo})`, 'criar');
          this.carregarProdutos();
          this.fecharFormulario();
        },
        error: err => {
          this.error = 'Erro ao criar produto: ' + (err.message || 'Erro desconhecido');
          this.auditoriaService.registrar('Criar Produto - Erro', `Falha ao criar ${this.form.descricao}: ${this.error}`, 'outro');
          this.loading = false;
        }
      });
    }
  }
  editarProduto(produto) {
    this.editingId = produto.id;
    this.form = {
      ...produto
    };
    this.showForm = true;
  }
  deletarProduto(id) {
    const produto = this.produtos.find(p => p.id === id);
    if (!confirm('Tem certeza que deseja deletar este produto?')) {
      return;
    }
    this.loading = true;
    this.error = '';
    this.estoqueService.deletarProduto(id).subscribe({
      next: () => {
        this.auditoriaService.registrar('Deletar Produto', `Produto ${produto?.descricao} deletado`, 'deletar');
        this.carregarProdutos();
      },
      error: err => {
        this.error = 'Erro ao deletar produto: ' + (err.message || 'Erro desconhecido');
        this.auditoriaService.registrar('Deletar Produto - Erro', `Falha ao deletar ${produto?.descricao}: ${this.error}`, 'outro');
        this.loading = false;
      }
    });
  }
  get produtosFiltrados() {
    let filtrados = this.produtos;
    if (this.filtroCodigo) {
      filtrados = filtrados.filter(p => p.codigo.toString().includes(this.filtroCodigo));
